INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'connectez-ecoles',
  'fr',
  'connectez-ecoles',
  '🎓 Connectez Écoles Madagascar',
  'Connectivité internet et énergie solaire pour 500 écoles rurales, avec formation des enseignants au numérique éducatif.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 Le problème","heading_style":"warm","intro":"Madagascar affiche l''un des taux d''accès au numérique scolaire les plus bas d''Afrique. 67 % des écoles rurales fonctionnent sans électricité, rendant tout équipement technologique inutilisable. Pendant ce temps, les plans gouvernementaux financent des tablettes qui resteront dans des caisses.","bullets":["67 % des écoles rurales sans électricité (source : MENB 2025)","14 % seulement de couverture internet nationale","82 % des enseignants du primaire sans formation numérique","Fracture numérique croissante entre urbain et rural","Plans publics qui équipent sans infrastructurer — dépense sans impact"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Notre solution","heading_style":"teal","intro":"GoV Gen Z Madagascar propose une approche en 3 piliers séquencés : d''abord l''infrastructure, ensuite les outils, enfin la formation. Pas de tablettes sans électricité.","bullets":["Pilier 1 — Électrification solaire : panels solaires off-grid pour 500 écoles, priorité DIANA, SAVA, ATSIMO ANDREFANA","Pilier 2 — Connectivité : 4G ou fibre selon la zone, avec routeurs robustifiés pour milieu rural","Pilier 3 — Formation pédagogique : 15 000 enseignants formés en 24 mois, partenariat universités locales + diaspora tech"],"extra_paragraphs":["Chaque école reçoit un kit complet (énergie + connexion + contenus locaux) et un enseignant référent formé. Un tableau de bord public suit l''avancement en temps réel."]},{"type":"budget_table","section_title":"💰 Budget détaillé","rows":[{"poste":"Électrification solaire","detail":"500 kits solaires off-grid, installation, maintenance 2 ans","montant":"400 000 000","row_class":""},{"poste":"Connectivité","detail":"500 connexions 4G\\/fibre, routeurs, abonnements 30 mois","montant":"250 000 000","row_class":""},{"poste":"Formation enseignants","detail":"15 000 enseignants × 3 jours de formation + matériel","montant":"120 000 000","row_class":""},{"poste":"Plateforme & contenus","detail":"Développement plateforme, contenus en malgache, hébergement","montant":"50 000 000","row_class":""},{"poste":"Suivi & évaluation","detail":"Tableau de bord public, audits trimestriels, rapports","montant":"30 000 000","row_class":""},{"poste":"TOTAL","detail":"","montant":"850 000 000","row_class":"total"}],"footnote":"Financement recherché : PTF, bailleurs bilatéraux, fonds diaspora. Budget validé par l''équipe Finances GoV Gen Z — audit indépendant planifié T3 2026."},{"type":"timeline","section_title":"📅 Calendrier","phases":[{"phase_label":"Phase 1","duration":"0 – 8 mois","step_title":"Pilote — 50 écoles région DIANA","body":"Installation des kits solaires, connexion 4G, formation 500 enseignants pilotes. Collecte des données de référence pour mesurer l''impact. Rapport public à M+8."},{"phase_label":"Phase 2","duration":"8 – 20 mois","step_title":"Déploiement — 250 écoles supplémentaires","body":"Extension vers SAVA, ATSIMO ANDREFANA, BETSIBOKA. Formation 7 500 enseignants supplémentaires. Lancement du tableau de bord public."},{"phase_label":"Phase 3","duration":"20 – 30 mois","step_title":"Finalisation — 200 écoles restantes + évaluation","body":"Couverture des 200 dernières écoles, formation des 7 000 enseignants restants, évaluation d''impact indépendante, publication du rapport final."}]},{"type":"kpi_grid","section_title":"📊 Indicateurs d''impact","heading_style":"teal","items":[{"value":"500","label":"Écoles connectées"},{"value":"15 000","label":"Enseignants formés"},{"value":"300 000","label":"Élèves bénéficiaires"},{"value":"10","label":"Régions couvertes"},{"value":"+40 %","label":"Résultats scolaires visés"},{"value":"100 %","label":"Audits publics"}]},{"type":"impact_tracker","section_title":"🎯 Suivi d''impact — Résultats actuels","heading_style":"teal","note":"Données au 12 mai 2026 · Phase 1 en cours · Mise à jour mensuelle","rows":[{"label":"Phase 1 — avancement","numbers":"38 % de la phase","bar_percent":38},{"label":"Écoles connectées","numbers":"15 \\/ 500","bar_percent":3},{"label":"Enseignants formés","numbers":"750 \\/ 15 000","bar_percent":5},{"label":"Budget activé","numbers":"120 M \\/ 850 M Ar","bar_percent":14},{"label":"Financement mobilisé","numbers":"14 % du budget","bar_percent":14}]},{"type":"team","section_title":"👥 Équipe projet","members":[{"name":"[Chef de projet — à renseigner]","role":"Coordination générale · Équipe Education"},{"name":"[Lead technique — à renseigner]","role":"Infrastructure solaire & connectivité · Équipe Digital"},{"name":"[Responsable formation — à renseigner]","role":"Programme enseignants · Partenariats universités"},{"name":"+ 124 volontaires actifs","role":"Terrain, logistique, formation, communication"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["MENB 2025 : Rapport national sur l''accès aux infrastructures scolaires","INSTAT 2024 : Données couverture internet par région","Concept note : Disponible sur demande — projets@govgenz.org","Budget détaillé : Fichier Excel disponible sur demande PTF","Rapport pilote : À publier M+8 (novembre 2026)"]}]',
  'actif',
  'published',
  'education,digital',
  127,
  '850 M Ar',
  '10 régions',
  '2026-03-01',
  30,
  38,
  '🎓 Connectez Écoles Madagascar',
  'Connectez Écoles Madagascar — Connectivité et énergie solaire pour 500 écoles rurales. GoV Gen Z Madagascar.',
'2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'connectez-ecoles',
  'en',
  'connectez-ecoles',
  '🎓 Connect Schools Madagascar',
  'Internet connectivity and solar power for 500 rural schools, with teacher training in digital education.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 The challenge","heading_style":"warm","intro":"Madagascar has one of the lowest rates of digital access in schools in Africa. 67% of rural schools have no electricity, so any technology investment sits unused. Meanwhile, public plans often fund devices without infrastructure.","bullets":["67% of rural schools without electricity (illustrative baseline)","14% national internet coverage (illustrative)","82% of primary teachers without digital training (illustrative)","Growing urban–rural digital divide"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Our approach","heading_style":"teal","intro":"GoV Gen Z Madagascar sequences three pillars: first infrastructure, then tools, then training. No tablets without power.","bullets":["Pillar 1 — Solar electrification: off-grid solar for 500 schools, priority regions","Pillar 2 — Connectivity: 4G or fibre where feasible, hardened routers for rural sites","Pillar 3 — Teacher training: 15,000 teachers over 24 months, local universities + diaspora tech partners"],"extra_paragraphs":[]},{"type":"budget_table","section_title":"💰 Budget overview","rows":[{"poste":"Solar electrification","detail":"500 off-grid kits, installation, 2-year maintenance","montant":"400 000 000","row_class":""},{"poste":"Connectivity","detail":"500 links, routers, 30-month subscriptions","montant":"250 000 000","row_class":""},{"poste":"Teacher training","detail":"15,000 teachers × 3 days + materials","montant":"120 000 000","row_class":""},{"poste":"TOTAL (illustrative)","detail":"","montant":"850 000 000","row_class":"total"}],"footnote":""},{"type":"kpi_grid","section_title":"📊 Impact snapshot","heading_style":"teal","items":[{"value":"500","label":"Schools targeted"},{"value":"15 000","label":"Teachers trained"},{"value":"10","label":"Regions"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["Concept note: on request — projets@govgenz.org"]}]',
  'actif',
  'published',
  'education,digital',
  127,
  '850 M Ar',
  '10 regions',
  '2026-03-01',
  30,
  38,
  '🎓 Connect Schools Madagascar',
  'Connect Schools Madagascar — connectivity and solar power for 500 rural schools. GoV Gen Z Madagascar.',
'2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'agrotech-jeunesse',
  'fr',
  'agrotech-jeunesse',
  '🌾 Agrotech Jeunesse',
  'Former 1 000 jeunes agriculteurs avec technologies durables, semences améliorées et accès direct aux marchés via une plateforme digitale.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 Le problème","heading_style":"warm","intro":"Madagascar consacre 70 % de sa population active à l''agriculture, mais reste structurellement dépendant des importations alimentaires. Les jeunes ruraux quittent l''agriculture faute d''accès aux techniques modernes, aux marchés et à un revenu décent. Le secteur vieillit pendant que la jeunesse cherche Antananarivo.","bullets":["70 % de la population active dans l''agriculture (INSTAT 2024)","48 % des ménages ruraux en insécurité alimentaire (FAO 2025)","Rendements du riz 2× inférieurs à la moyenne sub-saharienne","Moins de 8 % des jeunes de 18-35 ans restent en agriculture rurale","Accès quasi nul aux marchés d''exportation et prix garantis"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Notre solution","heading_style":"teal","intro":"Agrotech Jeunesse forme des jeunes agriculteurs en combinant savoir technique, outils numériques et débouchés commerciaux garantis. Pas de formation déconnectée du terrain — chaque module est ancré dans des résultats mesurables.","bullets":["Pilier 1 — Formation agronomique : 6 mois de formation en techniques durables (SRI, agroforesterie, compostage), semences certifiées, et gestion des intrants","Pilier 2 — Outils numériques : Application mobile MahasaFarm (météo agricole, prix marché, conseils agronomiques), tablettes subventionnées pour les groupements","Pilier 3 — Marché garanti : Plateforme de mise en relation directe producteurs-acheteurs, contrats avec restaurateurs et exportateurs, fonds de garantie prix plancher"],"extra_paragraphs":["Les 1 000 jeunes formés deviennent des \\"agrotech leaders\\" dans leurs communes — chacun transmet ensuite les techniques à 5 autres agriculteurs de son entourage."]},{"type":"budget_table","section_title":"💰 Budget détaillé","rows":[{"poste":"Formation agronomique","detail":"1 000 jeunes × 6 mois, formateurs, centres de formation","montant":"150 000 000","row_class":""},{"poste":"Semences & intrants","detail":"Semences améliorées certifiées + kits de démarrage par participant","montant":"80 000 000","row_class":""},{"poste":"Application MahasaFarm","detail":"Développement, maintenance 2 ans, hébergement, 1 000 licences","montant":"60 000 000","row_class":""},{"poste":"Équipement numérique","detail":"200 tablettes pour groupements + subvention data mobile","montant":"55 000 000","row_class":""},{"poste":"Plateforme marché","detail":"Développement plateforme, mise en relation, fonds prix plancher","montant":"50 000 000","row_class":""},{"poste":"Suivi & évaluation","detail":"Monitoring terrain, audits semestriels, rapport d''impact","montant":"25 000 000","row_class":""},{"poste":"TOTAL","detail":"","montant":"420 000 000","row_class":"total"}],"footnote":"Co-financement visé : FIDA, FAO, Union Européenne (fonds développement rural). Budget validé équipe Finance GoV Gen Z."},{"type":"timeline","section_title":"📅 Calendrier","phases":[{"phase_label":"Phase 1","duration":"0 – 6 mois","step_title":"Pilote — 200 jeunes, Vakinankaratra","body":"Sélection et formation de la première cohorte. Test de l''application MahasaFarm. Signature des premiers contrats marché garanti. Rapport d''étape à M+6."},{"phase_label":"Phase 2","duration":"6 – 16 mois","step_title":"Extension — 600 jeunes supplémentaires","body":"Déploiement vers Itasy et Bongolava. Lancement de la plateforme marché. Premières récoltes avec revenus garantis mesurés. Publication des résultats."},{"phase_label":"Phase 3","duration":"16 – 24 mois","step_title":"Finalisation — 200 derniers participants + évaluation","body":"Formation des 200 derniers participants. Activation du réseau \\"agrotech leaders\\" pour transmission aux 5 000 agriculteurs entourage. Évaluation d''impact finale."}]},{"type":"kpi_grid","section_title":"📊 Indicateurs d''impact","heading_style":"teal","items":[{"value":"1 000","label":"Jeunes formés"},{"value":"5 000","label":"Agriculteurs en cascade"},{"value":"+60 %","label":"Rendement visé"},{"value":"3 régions","label":"Couverture géographique"},{"value":"+80 %","label":"Revenu agricole visé"},{"value":"100 %","label":"Audits publics"}]},{"type":"impact_tracker","section_title":"🎯 Suivi d''impact — Résultats actuels","heading_style":"teal","note":"Données au 12 mai 2026 · Phase 1 en cours · Mise à jour mensuelle","rows":[{"label":"Phase 1 — avancement","numbers":"55 % de la phase","bar_percent":55},{"label":"Jeunes agriculteurs formés","numbers":"110 \\/ 1 000","bar_percent":11},{"label":"Utilisateurs app MahasaFarm","numbers":"95 \\/ 1 000","bar_percent":10},{"label":"Hausse rendement (pilote)","numbers":"+38 % \\/ obj. +60 %","bar_percent":63},{"label":"Budget activé","numbers":"105 M \\/ 420 M Ar","bar_percent":25}]},{"type":"team","section_title":"👥 Équipe projet","members":[{"name":"[Chef de projet — à renseigner]","role":"Coordination générale · Équipe Food"},{"name":"[Lead agronomique — à renseigner]","role":"Formation technique, partenariats instituts agronomiques"},{"name":"[Lead digital — à renseigner]","role":"Application MahasaFarm · Équipe Digital"},{"name":"+ 86 volontaires actifs","role":"Terrain, formation, logistique, suivi marché"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["INSTAT 2024 : Enquête nationale emploi et agriculture","FAO 2025 : Rapport sécurité alimentaire Madagascar","MAEP : Données rendements céréales par région","Concept note : Disponible sur demande — projets@govgenz.org","Budget détaillé : Fichier Excel disponible sur demande PTF","Rapport pilote : À publier M+6 (juillet 2026)"]}]',
  'actif',
  'published',
  'food,economy',
  89,
  '420 M Ar',
  'Vakinankaratra',
  '2026-01-01',
  24,
  55,
  '🌾 Agrotech Jeunesse',
  'Agrotech Jeunesse — Former 1 000 jeunes agriculteurs avec technologies durables. GoV Gen Z Madagascar.',
'2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'agrotech-jeunesse',
  'en',
  'agrotech-jeunesse',
  '🌾 Agrotech Youth',
  'Train 1,000 young farmers with sustainable techniques, improved seed, and direct market access through a digital platform.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 The challenge","heading_style":"warm","intro":"Most of Madagascar’s workforce depends on agriculture, yet productivity and youth retention in rural farming remain low. Young people leave farming without access to modern techniques, markets, or fair income.","bullets":["Low yields compared with regional benchmarks","Limited access to export markets and stable prices","Weak digital tools for weather, prices, and agronomy"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Our approach","heading_style":"teal","intro":"Agrotech Youth combines agronomy, digital tools, and guaranteed market linkages. Every module ties to measurable outcomes.","bullets":["Pillar 1 — Agronomy training: sustainable techniques, certified seed, input management","Pillar 2 — Digital tools: mobile app for weather, market prices, and advice; tablets for cooperatives","Pillar 3 — Market access: direct buyer matching, contracts, floor-price guarantee fund"],"extra_paragraphs":[]},{"type":"budget_table","section_title":"💰 Budget overview","rows":[{"poste":"Agronomy training","detail":"1,000 young farmers × 6 months","montant":"150 000 000","row_class":""},{"poste":"Seed & inputs","detail":"Certified seed and starter kits","montant":"80 000 000","row_class":""},{"poste":"Mobile platform","detail":"Development, hosting, licences","montant":"60 000 000","row_class":""},{"poste":"TOTAL (illustrative)","detail":"","montant":"420 000 000","row_class":"total"}],"footnote":""},{"type":"kpi_grid","section_title":"📊 Impact snapshot","heading_style":"teal","items":[{"value":"1 000","label":"Youth trained"},{"value":"3","label":"Regions"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["Concept note: on request — projets@govgenz.org"]}]',
  'actif',
  'published',
  'food,economy',
  89,
  '420 M Ar',
  'Vakinankaratra',
  '2026-01-01',
  24,
  55,
  '🌾 Agrotech Youth',
  'Agrotech Youth — train 1,000 young farmers with sustainable tech, improved seed, and market access. GoV Gen Z Madagascar.',
'2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'eau-potable-2026',
  'fr',
  'eau-potable-2026',
  '💧 Eau Potable 2026',
  'Construction de 50 points d''eau potable dans les Hauts Plateaux avec formation locale en maintenance et gouvernance communautaire.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 Le problème","heading_style":"warm","intro":"Dans les Hauts Plateaux de Madagascar, 63 % des ménages ruraux n''ont pas accès à l''eau potable. Les femmes et enfants parcourent en moyenne 4 km par jour pour aller chercher de l''eau, au détriment de la scolarisation et de la productivité. Les maladies hydriques représentent 28 % des hospitalisations en zone rurale.","bullets":["63 % des ménages ruraux des Hauts Plateaux sans eau potable (JIRAMA 2024)","4 km de trajet moyen quotidien pour l''eau (WASH Madagascar 2024)","28 % des hospitalisations liées aux maladies hydriques (Ministère Santé 2025)","Taux de mortalité infantile × 3 dans les zones sans eau sécurisée","Points d''eau existants : 40 % hors service faute de maintenance locale formée"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Notre solution","heading_style":"teal","intro":"Eau Potable 2026 ne construit pas seulement des forages — il construit des systèmes durables. Chaque point d''eau est accompagné d''une gouvernance communautaire et d''une équipe formée à la maintenance.","bullets":["Pilier 1 — Construction : 50 forages équipés de pompes manuelles robustifiées pour milieu rural, avec bassins de décantation et clôtures de protection sanitaire","Pilier 2 — Maintenance locale : 2 techniciens locaux formés par point d''eau (100 personnes au total) avec kit d''outils et guide de maintenance en malgache","Pilier 3 — Gouvernance communautaire : Comité de gestion de l''eau élu par commune, cotisation communautaire pour fond de maintenance, suivi de la qualité mensuel"],"extra_paragraphs":["Un tableau de bord numérique simple (SMS + web) permet de signaler les pannes et suivre l''état des 50 points d''eau en temps réel."]},{"type":"budget_table","section_title":"💰 Budget détaillé","rows":[{"poste":"Forage & équipement","detail":"50 forages × coût moyen (pompe, dalle, clôture)","montant":"175 000 000","row_class":""},{"poste":"Formation maintenance","detail":"100 techniciens locaux × 5 jours + kits outils","montant":"35 000 000","row_class":""},{"poste":"Gouvernance communautaire","detail":"Formation comités, guides malgaches, ateliers","montant":"20 000 000","row_class":""},{"poste":"Analyse qualité eau","detail":"Tests qualité initiaux + 2 campagnes de contrôle annuelles","montant":"25 000 000","row_class":""},{"poste":"Suivi numérique","detail":"Tableau de bord SMS\\/web, maintenance 18 mois","montant":"15 000 000","row_class":""},{"poste":"Logistique & études terrain","detail":"Études hydrogéologiques préalables, transport, coordination","montant":"10 000 000","row_class":""},{"poste":"TOTAL","detail":"","montant":"280 000 000","row_class":"total"}],"footnote":"Financement visé : UNICEF WASH, AFD, partenaires bilatéraux. Dossier en cours de finalisation — validation prévue Q3 2026."},{"type":"timeline","section_title":"📅 Calendrier","phases":[{"phase_label":"Phase 0","duration":"Maintenant – 2 mois","step_title":"Validation du dossier candidat","body":"Instruction du dossier par l''équipe GoV Gen Z, études hydrogéologiques préliminaires, identification des 50 sites prioritaires avec les communes partenaires."},{"phase_label":"Phase 1","duration":"M+2 – M+10","step_title":"Construction — 25 premiers forages","body":"Forage, équipement, dalles de protection. Formation des 50 premiers techniciens locaux. Mise en place des comités de gestion. Rapport intermédiaire public."},{"phase_label":"Phase 2","duration":"M+10 – M+18","step_title":"Construction — 25 forages restants + évaluation","body":"Déploiement des 25 derniers points d''eau. Formation des 50 techniciens restants. Évaluation d''impact indépendante. Publication rapport final."}]},{"type":"kpi_grid","section_title":"📊 Indicateurs d''impact","heading_style":"teal","items":[{"value":"50","label":"Points d''eau construits"},{"value":"25 000","label":"Ménages bénéficiaires"},{"value":"100","label":"Techniciens formés"},{"value":"-60 %","label":"Maladies hydriques visées"},{"value":"-4 km","label":"Trajet quotidien économisé"},{"value":"100 %","label":"Gouvernance communautaire"}]},{"type":"note_panel","section_title":"🎯 Suivi d''impact","heading_style":"teal","message":"📊 Le suivi d''impact sera activédès le démarrage officiel du projet. Statut actuel : en attente de validation","submessage":""},{"type":"team","section_title":"👥 Équipe projet","members":[{"name":"[Chef de projet — à renseigner]","role":"Coordination générale · Équipe Water"},{"name":"[Expert hydrogéologue — à renseigner]","role":"Études terrain, sélection sites, supervision technique"},{"name":"[Responsable communautaire — à renseigner]","role":"Formation comités de gestion · Équipe Territories"},{"name":"+ 42 volontaires actifs","role":"Terrain, suivi qualité, formation, communication"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["JIRAMA 2024 : Rapport accès eau potable par région","WASH Madagascar 2024 : Données distance collecte eau","Ministère de la Santé 2025 : Rapport maladies hydriques","Concept note : Disponible sur demande — projets@govgenz.org","Budget détaillé : Fichier Excel disponible sur demande PTF","Rapport démarrage : À publier M+2 (dès validation)"]}]',
  'candidat',
  'draft',
  'water,health',
  45,
  '280 M Ar',
  'Hauts Plateaux',
  '2026-04-01',
  18,
  0,
  '💧 Eau Potable 2026',
  'Eau Potable 2026 — 50 points d''eau potable dans les Hauts Plateaux. GoV Gen Z Madagascar.',
NULL,
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'eau-potable-2026',
  'en',
  'eau-potable-2026',
  '💧 Drinking Water 2026',
  'Build 50 safe water points in the Central Highlands with local maintenance training and community governance.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 The challenge","heading_style":"warm","intro":"In the Central Highlands, many rural households still lack reliable access to safe drinking water. Long daily walks to fetch water affect schooling and productivity; waterborne disease burden remains high.","bullets":["Distance and time cost for water collection","Existing points often fall out of service without trained maintenance","Need for community governance and quality monitoring"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Our approach","heading_style":"teal","intro":"We build durable systems, not one-off boreholes: each point includes local maintenance capacity and a water committee.","bullets":["Pillar 1 — Construction: 50 equipped boreholes with hand pumps, protection, fencing","Pillar 2 — Local maintenance: two trained technicians per point (100 people total) with toolkits","Pillar 3 — Governance: elected committees, small maintenance fund, monthly quality checks"],"extra_paragraphs":[]},{"type":"budget_table","section_title":"💰 Budget overview","rows":[{"poste":"Boreholes & equipment","detail":"50 sites, pumps, slabs, fencing","montant":"175 000 000","row_class":""},{"poste":"Maintenance training","detail":"100 technicians × 5 days + toolkits","montant":"35 000 000","row_class":""},{"poste":"TOTAL (illustrative)","detail":"","montant":"280 000 000","row_class":"total"}],"footnote":""},{"type":"note_panel","section_title":"🎯 Impact tracking","heading_style":"teal","message":"📊 Impact tracking will startonce the project is officially launched. Current status: candidate \\/ pending validation","submessage":""},{"type":"sources","section_title":"📎 Sources & documents","lines":["Concept note: on request — projets@govgenz.org"]}]',
  'candidat',
  'draft',
  'water,health',
  45,
  '280 M Ar',
  'Central Highlands',
  '2026-04-01',
  18,
  0,
  '💧 Drinking Water 2026',
  'Drinking Water 2026 — 50 safe water points in the Central Highlands with local maintenance and community governance. GoV Gen Z Madagascar.',
