INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'energie-solaire',
  'fr',
  'energie-solaire',
  '⚡ Énergie Solaire Communautaire',
  '200 mini-grids solaires en zones isolées pour créer des emplois locaux et réduire les émissions de CO₂ de manière mesurable.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 Le problème","heading_style":"warm","intro":"Madagascar présente l''un des taux d''électrification les plus bas du monde. 75 % de la population n''a pas accès à l''électricité, un chiffre qui monte à 92 % en zones rurales isolées. Les groupes électrogènes à gasoil sont la seule alternative — coûteux, polluants et fragiles logistiquement.","bullets":["75 % de la population sans électricité (Banque Mondiale 2024)","92 % des zones rurales isolées sans accès réseau JIRAMA","Le gasoil représente 60-80 % des coûts opérationnels des PME rurales","Cliniques rurales sans réfrigération pour vaccins — chaîne du froid brisée","Madagascar parmi les pays les plus exposés aux impacts du changement climatique"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Notre solution","heading_style":"teal","intro":"Chaque mini-grid solaire est dimensionné pour alimenter un village entier — habitations, école, dispensaire, commerces. Pas de solution ponctuelle : une infrastructure durable avec maintenance locale.","bullets":["Pilier 1 — Infrastructure mini-grid : 200 micro-réseaux solaires avec batteries lithium, câblage de distribution basse tension, compteurs prépayés par ménage","Pilier 2 — Emplois locaux : 400 techniciens énergétiques formés (2 par village), certifiés, salariés par le comité de gestion communautaire","Pilier 3 — Gouvernance & financement : Système de paiement mobile M-Cash pour les abonnements, fonds de renouvellement alimenté par les cotisations, audit annuel des émissions évitées"],"extra_paragraphs":["Chaque mini-grid est conçu pour une durée de vie de 20 ans. Les émissions de CO₂ évitées sont documentées pour valorisation carbone."]},{"type":"budget_table","section_title":"💰 Budget détaillé","rows":[{"poste":"Équipement solaire","detail":"200 mini-grids (panneaux, batteries, onduleurs, câblage)","montant":"600 000 000","row_class":""},{"poste":"Installation & génie civil","detail":"Structures, pylônes, câblage distribution, connexions ménages","montant":"150 000 000","row_class":""},{"poste":"Formation techniciens","detail":"400 techniciens × 3 mois de formation + certification","montant":"80 000 000","row_class":""},{"poste":"Système paiement mobile","detail":"Intégration M-Cash, compteurs prépayés, maintenance 3 ans","montant":"40 000 000","row_class":""},{"poste":"Gouvernance communautaire","detail":"Formation comités, guides, ateliers, fonds de renouvellement initial","montant":"30 000 000","row_class":""},{"poste":"Suivi & mesure CO₂","detail":"Monitoring émissions, audit annuel, rapport carbone","montant":"20 000 000","row_class":""},{"poste":"TOTAL","detail":"","montant":"920 000 000","row_class":"total"}],"footnote":"Financement visé : Green Climate Fund, AFD énergie, partenaires bilatéraux. Valorisation carbone prévue pour autofinancement partiel des phases 2 et 3."},{"type":"timeline","section_title":"📅 Calendrier","phases":[{"phase_label":"Phase 1","duration":"0 – 10 mois","step_title":"Pilote — 40 mini-grids, région DIANA","body":"Déploiement des 40 premiers mini-grids dans les communes les plus isolées de DIANA. Formation des 80 premiers techniciens. Lancement du système M-Cash. Mesure initiale des émissions évitées. Rapport public à M+10."},{"phase_label":"Phase 2","duration":"10 – 24 mois","step_title":"Extension — 100 mini-grids supplémentaires","body":"Déploiement vers ATSIMO ANDREFANA et ANDROY. Formation des 200 techniciens supplémentaires. Publication du premier rapport d''impact et de la valorisation carbone."},{"phase_label":"Phase 3","duration":"24 – 36 mois","step_title":"Finalisation — 60 derniers mini-grids + évaluation","body":"Couverture des 60 derniers villages. Formation des 120 techniciens restants. Évaluation d''impact indépendante. Publication du rapport final + dossier carbone."}]},{"type":"kpi_grid","section_title":"📊 Indicateurs d''impact","heading_style":"teal","items":[{"value":"200","label":"Mini-grids déployés"},{"value":"80 000","label":"Ménages électrifiés"},{"value":"400","label":"Emplois créés"},{"value":"-60 %","label":"Coûts énergie PME rurales"},{"value":"15 000 T","label":"CO₂ évitées \\/ an"},{"value":"20 ans","label":"Durée de vie infrastructure"}]},{"type":"impact_tracker","section_title":"🎯 Suivi d''impact — Résultats actuels","heading_style":"teal","note":"Données au 12 mai 2026 · Phase 1 en cours · Mise à jour mensuelle","rows":[{"label":"Phase 1 — avancement","numbers":"22 % de la phase","bar_percent":22},{"label":"Mini-grids déployés","numbers":"9 \\/ 200","bar_percent":5},{"label":"Ménages électrifiés","numbers":"3 600 \\/ 80 000","bar_percent":5},{"label":"Techniciens formés","numbers":"18 \\/ 400","bar_percent":5},{"label":"CO₂ évitées (annualisées)","numbers":"1 350 T \\/ 15 000 T\\/an","bar_percent":9}]},{"type":"team","section_title":"👥 Équipe projet","members":[{"name":"[Chef de projet — à renseigner]","role":"Coordination générale · Équipe Energy"},{"name":"[Ingénieur solaire — à renseigner]","role":"Dimensionnement des mini-grids, supervision technique"},{"name":"[Expert carbone — à renseigner]","role":"Mesure CO₂, dossier valorisation · Équipe Environment"},{"name":"+ 153 volontaires actifs","role":"Terrain, installation, formation, suivi, communication"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["Banque Mondiale 2024 : Rapport accès énergie Madagascar","ADER Madagascar : Données électrification rurale par région","IRENA 2024 : Coûts solaire off-grid Afrique subsaharienne","Concept note : Disponible sur demande — projets@govgenz.org","Budget détaillé : Fichier Excel disponible sur demande PTF","Rapport pilote : À publier M+10 (décembre 2026)"]}]',
  'actif',
  'published',
  'energy,environment',
  156,
  '920 M Ar',
  'Sud & DIANA',
  '2026-02-01',
  36,
  22,
  '⚡ Énergie Solaire Communautaire',
  'Énergie Solaire Communautaire — 200 mini-grids solaires en zones isolées. GoV Gen Z Madagascar.',
'2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'energie-solaire',
  'en',
  'energie-solaire',
  '⚡ Community Solar Energy',
  '200 solar mini-grids in isolated areas to create local jobs and reduce CO₂ emissions in a measurable way.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 The challenge","heading_style":"warm","intro":"Electrification rates remain low; isolated rural areas depend on expensive, polluting diesel generators. Reliable clean power unlocks clinics, schools, and small enterprises.","bullets":["High share of energy cost in rural SME budgets","Broken cold chains for vaccines without stable electricity","Climate exposure and need for long-lived infrastructure"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Our approach","heading_style":"teal","intro":"Each mini-grid is sized for a whole village cluster — homes, school, clinic, small shops — with local maintenance jobs.","bullets":["Pillar 1 — Mini-grid hardware: solar + batteries + low-voltage distribution + prepaid metering","Pillar 2 — Local jobs: trained village energy technicians employed by community committees","Pillar 3 — Governance & finance: mobile payments, renewal fund, annual emissions audit"],"extra_paragraphs":[]},{"type":"budget_table","section_title":"💰 Budget overview","rows":[{"poste":"Solar equipment","detail":"200 mini-grids (panels, batteries, inverters, wiring)","montant":"600 000 000","row_class":""},{"poste":"Installation","detail":"Civil works, distribution, household connections","montant":"150 000 000","row_class":""},{"poste":"TOTAL (illustrative)","detail":"","montant":"920 000 000","row_class":"total"}],"footnote":""},{"type":"kpi_grid","section_title":"📊 Impact snapshot","heading_style":"teal","items":[{"value":"200","label":"Mini-grids"},{"value":"80 000","label":"Households targeted"},{"value":"400","label":"Technician jobs"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["Concept note: on request — projets@govgenz.org"]}]',
  'actif',
  'published',
  'energy,environment',
  156,
  '920 M Ar',
  'South & DIANA',
  '2026-02-01',
  36,
  22,
  '⚡ Community Solar Energy',
  'Community Solar Energy — 200 solar mini-grids in isolated areas for local jobs and measurable CO₂ reductions. GoV Gen Z Madagascar.',
'2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'acces-justice',
  'fr',
  'acces-justice',
  '⚖️ Accès à la Justice — Jeunes',
  '500 jeunes paralegals formés et 20 centres d''aide juridique gratuite dans les zones reculées pour garantir l''accès à la justice.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 Le problème","heading_style":"warm","intro":"À Madagascar, la justice est structurellement inaccessible pour la majorité. 76 % des citoyens n''ont jamais consulté un professionnel juridique, faute de proximité géographique, de coût, ou de barrières linguistiques. Les jeunes, les femmes et les ruraux sont les plus exposés aux abus sans recours.","bullets":["76 % des Malgaches sans accès à un conseiller juridique (PNUD 2024)","1 avocat pour 50 000 habitants hors Antananarivo","Délais judiciaires moyens de 3-5 ans en première instance","Les fonciers non titrés représentent 80 % des litiges ruraux non résolus","Taux de récidive carcérale à 58 % — absence de suivi post-peine"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Notre solution","heading_style":"teal","intro":"Accès à la Justice — Jeunes déploie une infrastructure juridique de proximité — des paralegals formés dans chaque commune prioritaire et des centres physiques pour les cas complexes. Simple, accessible, en malgache.","bullets":["Pilier 1 — Formation paralegals : 500 jeunes paralegals formés en 3 mois (droits fondamentaux, procédures administratives, médiation foncière), déployés dans leur commune d''origine","Pilier 2 — Centres d''aide juridique : 20 centres physiques dans les chefs-lieux de district les plus défavorisés, staffés par un juriste GoV Gen Z + paralegals locaux, consultation gratuite","Pilier 3 — Outils numériques : Application \\"Zo Malgache\\" (droits en malgache), ligne SMS de première orientation juridique, base de données jurisprudence locale"],"extra_paragraphs":["Les paralegals ne remplacent pas les avocats — ils orientent, accompagnent les démarches administratives, et réfèrent aux juristes pour les cas complexes."]},{"type":"budget_table","section_title":"💰 Budget détaillé","rows":[{"poste":"Formation paralegals","detail":"500 paralegals × 3 mois + formateurs juristes, matériel pédagogique","montant":"70 000 000","row_class":""},{"poste":"Centres d''aide juridique","detail":"20 centres — loyer 2 ans, mobilier, équipement bureautique","montant":"60 000 000","row_class":""},{"poste":"Application Zo Malgache","detail":"Développement, contenu juridique malgache, maintenance 2 ans","montant":"30 000 000","row_class":""},{"poste":"Ligne SMS orientation","detail":"Infrastructure SMS, opérateur, 24 mois de service","montant":"15 000 000","row_class":""},{"poste":"Juristes référents","detail":"4 juristes GoV Gen Z à mi-temps × 24 mois","montant":"12 000 000","row_class":""},{"poste":"Suivi & évaluation","detail":"Monitoring terrain, rapport d''impact semestriel, audit","montant":"8 000 000","row_class":""},{"poste":"TOTAL","detail":"","montant":"195 000 000","row_class":"total"}],"footnote":"Financement visé : PNUD Madagascar, USAID, Open Society Foundations. Dossier en cours de validation GoV Gen Z — décision prévue Q3 2026."},{"type":"timeline","section_title":"📅 Calendrier","phases":[{"phase_label":"Phase 0","duration":"Maintenant – 3 mois","step_title":"Validation & préparation","body":"Finalisation du dossier de validation GoV Gen Z. Identification des 20 sites prioritaires. Recrutement des juristes référents. Partenariats universités de droit."},{"phase_label":"Phase 1","duration":"M+3 – M+12","step_title":"Pilote — 200 paralegals + 8 centres","body":"Première cohorte de 200 paralegals formés et déployés. Ouverture des 8 premiers centres dans les districts pilotes. Lancement de l''application Zo Malgache. Rapport public M+12."},{"phase_label":"Phase 2","duration":"M+12 – M+24","step_title":"Extension — 300 paralegals + 12 centres","body":"Formation des 300 paralegals restants. Ouverture des 12 derniers centres. Évaluation d''impact indépendante. Publication rapport final."}]},{"type":"kpi_grid","section_title":"📊 Indicateurs d''impact","heading_style":"teal","items":[{"value":"500","label":"Paralegals formés"},{"value":"20","label":"Centres d''aide juridique"},{"value":"50 000","label":"Consultations prévues \\/ an"},{"value":"114 districts","label":"Couverture nationale"},{"value":"Gratuit","label":"Toutes consultations"},{"value":"100 %","label":"En langue malgache"}]},{"type":"note_panel","section_title":"🎯 Suivi d''impact","heading_style":"teal","message":"📊 Le suivi d''impact sera activédès le démarrage officiel du projet. Statut actuel : en cours de validation","submessage":""},{"type":"team","section_title":"👥 Équipe projet","members":[{"name":"[Chef de projet — à renseigner]","role":"Coordination générale · Équipe Legal"},{"name":"[Juriste principal — à renseigner]","role":"Conception curriculum, formation paralegals, référent cas complexes"},{"name":"[Lead tech — à renseigner]","role":"Application Zo Malgache · Équipe Digital"},{"name":"+ 64 volontaires actifs","role":"Terrain, orientation juridique, communication, suivi"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["PNUD 2024 : Rapport accès à la justice Madagascar","Ministère de la Justice 2025 : Données densité juridique par région","Baromètre Gouvernance 2024 : Perception de la justice par les jeunes","Concept note : Disponible sur demande — projets@govgenz.org","Budget détaillé : Fichier Excel disponible sur demande PTF","Décision validation : Prévue Q3 2026"]}]',
  'validation',
  'draft',
  'legal,citizen',
  67,
  '195 M Ar',
  'National',
  '2026-03-01',
  24,
  5,
  '⚖️ Accès à la Justice — Jeunes',
  'Accès à la Justice — Jeunes — 500 paralegals et 20 centres d''aide juridique. GoV Gen Z Madagascar.',
NULL,
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'acces-justice',
  'en',
  'acces-justice',
  '⚖️ Access to Justice — Youth',
  '500 trained youth paralegals and 20 free legal aid centres in remote areas to improve access to justice.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 The challenge","heading_style":"warm","intro":"Justice services are often physically and financially out of reach. Young people, women, and rural communities face disputes without guidance.","bullets":["Very few lawyers per capita outside the capital","Long case backlogs","Land and administrative disputes with no first-line support"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Our approach","heading_style":"teal","intro":"Train young paralegals for first-line orientation and mediation, backed by physical aid centres and a simple rights app in Malagasy.","bullets":["Pillar 1 — Paralegal training: 500 youth, 3-month curriculum (rights, admin procedures, land mediation)","Pillar 2 — Aid centres: 20 district hubs with a staff lawyer + local paralegals, free intake","Pillar 3 — Digital tools: “Zo Malgache” app, SMS triage line, local case-law notes"],"extra_paragraphs":[]},{"type":"budget_table","section_title":"💰 Budget overview","rows":[{"poste":"Paralegal training","detail":"500 × 3 months + trainers","montant":"70 000 000","row_class":""},{"poste":"Aid centres","detail":"20 centres, 24-month rent and equipment","montant":"60 000 000","row_class":""},{"poste":"TOTAL (illustrative)","detail":"","montant":"195 000 000","row_class":"total"}],"footnote":""},{"type":"note_panel","section_title":"🎯 Impact tracking","heading_style":"teal","message":"📊 Impact tracking will startonce validation is complete. Current status: under validation","submessage":""},{"type":"sources","section_title":"📎 Sources & documents","lines":["Concept note: on request — projets@govgenz.org"]}]',
  'validation',
  'draft',
  'legal,citizen',
  67,
  '195 M Ar',
  'National',
  '2026-03-01',
  24,
  5,
  '⚖️ Access to Justice — Youth',
  'Access to Justice — Youth: 500 trained paralegals and 20 free legal aid centres in remote areas. GoV Gen Z Madagascar.',
NULL,
  '2026-05-15 15:38:36',
  '2026-05-15 15:38:36',
  NULL
);

INSERT INTO project_projects (slug, locale, translation_group, title, excerpt, body, body_content_mode, body_blocks, project_status, publication_state, sectors_csv, volunteers_count, budget_display, geography, launched_at, duration_months, progress_percent, meta_title, meta_description, published_at, created_at, updated_at, deleted_at) VALUES (
  'sante-maternelle',
  'fr',
  'sante-maternelle',
  '🏥 Santé Maternelle+',
  'Renforcer 100 cliniques rurales pour réduire la mortalité maternelle de 40 % en 3 ans — équipements, formations, protocoles.',
  NULL,
  'blocks',
  '[{"type":"section_rich","heading":"📰 Le problème","heading_style":"warm","intro":"Madagascar affiche l''un des taux de mortalité maternelle les plus élevés au monde. 478 décès pour 100 000 naissances vivantes — contre une moyenne de 196 en Afrique subsaharienne. Dans ATSIMO ANDREFANA, ce chiffre dépasse les 700. La plupart de ces décès sont évitables.","bullets":["478\\/100 000 taux mortalité maternelle national (OMS 2024)","700+\\/100 000 dans ATSIMO ANDREFANA — région cible","Seulement 44 % des accouchements assistés par personnel qualifié (Ministère Santé 2025)","72 % des cliniques rurales sans équipement obstétrical minimal","Chaîne du froid brisée dans 60 % des centres de santé ruraux"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Notre solution","heading_style":"teal","intro":"Santé Maternelle+ adopte une approche systémique : équiper, former, protocolariser. Pas de matériel sans formation, pas de formation sans suivi de protocoles. Chaque clinique renforcée devient un centre de référence pour son district.","bullets":["Pilier 1 — Équipement des cliniques : Kits obstétricaux standardisés, réfrigérateurs solaires pour chaîne du froid vaccins, oxygène médical, tables d''accouchement, lampes chirurgicales","Pilier 2 — Formation des sages-femmes : 300 sages-femmes formées aux urgences obstétricales (SOUB), protocoles hémorragie post-partum, pré-éclampsie, dystocie — formations mensuelles en cascade","Pilier 3 — Protocoles & référencement : Guides de protocoles illustrés en malgache, système de référencement SMS vers hôpitaux de district, tableau de bord mortalité par clinique"],"extra_paragraphs":["Un suivi mensuel des indicateurs par clinique permet d''identifier rapidement les problèmes et d''adapter les formations en temps réel."]},{"type":"budget_table","section_title":"💰 Budget détaillé","rows":[{"poste":"Équipement cliniques","detail":"100 kits obstétricaux + réfrigérateurs solaires + consommables","montant":"380 000 000","row_class":""},{"poste":"Formation sages-femmes","detail":"300 sages-femmes × 5 jours SOUB + formations continues","montant":"120 000 000","row_class":""},{"poste":"Protocoles & guides","detail":"Conception, impression 2 000 guides malgache + français","montant":"30 000 000","row_class":""},{"poste":"Chaîne du froid","detail":"100 réfrigérateurs solaires + installation + maintenance 3 ans","montant":"150 000 000","row_class":""},{"poste":"Système SMS référencement","detail":"Infrastructure SMS, formation personnels, 36 mois service","montant":"40 000 000","row_class":""},{"poste":"Suivi & évaluation","detail":"Tableau de bord mortalité, audits trimestriels, rapport final","montant":"60 000 000","row_class":""},{"poste":"TOTAL","detail":"","montant":"780 000 000","row_class":"total"}],"footnote":"Financement visé : UNFPA, OMS Madagascar, Union Européenne (santé reproductive). Partenariats Médecins du Monde et MSF pour les formations SOUB."},{"type":"timeline","section_title":"📅 Calendrier","phases":[{"phase_label":"Phase 1","duration":"0 – 10 mois","step_title":"Pilote — 30 cliniques, districts prioritaires","body":"Sélection des 30 cliniques les plus critiques. Livraison et installation des équipements. Formation de 90 sages-femmes en SOUB. Mesure des données de référence pour comparaison d''impact. Rapport public M+10."},{"phase_label":"Phase 2","duration":"10 – 24 mois","step_title":"Extension — 50 cliniques supplémentaires","body":"Déploiement vers les 50 cliniques suivantes. Formation de 150 sages-femmes. Lancement du tableau de bord mortalité public. Publication rapport intermédiaire."},{"phase_label":"Phase 3","duration":"24 – 36 mois","step_title":"Finalisation — 20 cliniques restantes + évaluation","body":"Renforcement des 20 dernières cliniques. Formation des 60 sages-femmes restantes. Évaluation d''impact indépendante. Publication rapport final + recommandations politiques pour réplication nationale."}]},{"type":"kpi_grid","section_title":"📊 Indicateurs d''impact","heading_style":"teal","items":[{"value":"100","label":"Cliniques renforcées"},{"value":"300","label":"Sages-femmes formées"},{"value":"-40 %","label":"Mortalité maternelle visée"},{"value":"25 000","label":"Accouchements sécurisés \\/ an"},{"value":"100 %","label":"Chaîne du froid assurée"},{"value":"Mensuel","label":"Rapport mortalité public"}]},{"type":"impact_tracker","section_title":"🎯 Suivi d''impact — Résultats actuels","heading_style":"teal","note":"Données au 12 mai 2026 · Phase 1 en cours · Mise à jour mensuelle","rows":[{"label":"Phase 1 — avancement","numbers":"18 % de la phase","bar_percent":18},{"label":"Cliniques renforcées","numbers":"6 \\/ 100","bar_percent":6},{"label":"Sages-femmes formées (SOUB)","numbers":"16 \\/ 300","bar_percent":5},{"label":"Réduction mortalité (zones pilotes)","numbers":"−8 % \\/ obj. −40 %","bar_percent":20},{"label":"Chaîne du froid opérationnelle","numbers":"6 \\/ 100 cliniques","bar_percent":6}]},{"type":"team","section_title":"👥 Équipe projet","members":[{"name":"[Chef de projet — à renseigner]","role":"Coordination générale · Équipe Health"},{"name":"[Médecin référent — à renseigner]","role":"Supervision médicale, protocoles SOUB, formation sages-femmes"},{"name":"[Coordinateur terrain — à renseigner]","role":"Logistique équipements, suivi cliniques · Équipe Territories"},{"name":"+ 109 volontaires actifs","role":"Terrain, logistique, formation, suivi indicateurs, communication"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["OMS 2024 : Tendances mortalité maternelle 2000-2023","Ministère de la Santé Madagascar 2025 : Rapport santé maternelle et néonatale","UNFPA Madagascar : État des centres de santé materno-infantile","Concept note : Disponible sur demande — projets@govgenz.org","Budget détaillé : Fichier Excel disponible sur demande PTF","Rapport pilote : À publier M+10 (février 2027)"]}]',
