  'blocks',
  '[{"type":"section_rich","heading":"📰 The challenge","heading_style":"warm","intro":"Maternal mortality remains critically high; many deaths are preventable with basic equipment, protocols, and referral. Rural clinics lack minimal obstetric kits and reliable cold chains for vaccines.","bullets":["Low share of births attended by skilled staff in remote areas","Weak cold chain in rural health posts","Need for training, supervision, and monthly indicators"],"extra_paragraphs":[]},{"type":"section_rich","heading":"✅ Our approach","heading_style":"teal","intro":"A systemic model: equip, train, protocolise. No equipment roll-out without training; no training without follow-up.","bullets":["Pillar 1 — Clinic equipment: standard obstetric kits, solar fridges, oxygen where needed","Pillar 2 — Midwife training: emergencies (PPH, pre-eclampsia), monthly cascade sessions","Pillar 3 — Protocols & referral: illustrated Malagasy guides, SMS referral to district hospitals, public dashboard"],"extra_paragraphs":[]},{"type":"budget_table","section_title":"💰 Budget overview","rows":[{"poste":"Clinic equipment","detail":"100 kits + solar fridges + consumables","montant":"380 000 000","row_class":""},{"poste":"Midwife training","detail":"300 midwives × 5-day emergency course","montant":"120 000 000","row_class":""},{"poste":"TOTAL (illustrative)","detail":"","montant":"780 000 000","row_class":"total"}],"footnote":""},{"type":"kpi_grid","section_title":"📊 Impact snapshot","heading_style":"teal","items":[{"value":"100","label":"Clinics"},{"value":"300","label":"Midwives trained"},{"value":"−40%","label":"MMR target (3 yrs)"}]},{"type":"sources","section_title":"📎 Sources & documents","lines":["Concept note: on request — projets@govgenz.org"]}]',
